using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string PredictedCategory { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

namespace TicketClassifier.Models;

public class TicketRequest
{
    public string Subject { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Priority { get; set; }
}

namespace TicketClassifier.Models;

public class ClassificationResult
{
    public string PredictedCategory { get; set; } = string.Empty;
    public Dictionary<string, float> Confidence { get; set; } = new();
}

namespace TicketClassifier.Models;

public class EvaluationMetrics
{
    public double MacroAccuracy { get; set; }
    public double MicroAccuracy { get; set; }
    public double LogLoss { get; set; }
    public double LogLossReduction { get; set; }
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketClassifierService
{
    private readonly MLContext _mlContext;
    private readonly ILogger<TicketClassifierService> _logger;
    private ITransformer? _model;
    private EvaluationMetrics? _metrics;
    private string[]? _categoryLabels;

    public TicketClassifierService(ILogger<TicketClassifierService> logger)
    {
        _mlContext = new MLContext(seed: 42);
        _logger = logger;
    }

    public EvaluationMetrics? Metrics => _metrics;

    public void TrainModel(string dataPath)
    {
        var data = _mlContext.Data.LoadFromTextFile<TicketInput>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        // With a small dataset, train and evaluate on the full set to avoid
        // empty test splits. In production, use TrainTestSplit.
        var pipeline = _mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketInput.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "SubjectFeaturized", nameof(TicketInput.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "DescriptionFeaturized", nameof(TicketInput.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketInput.Priority)))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .Append(_mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));

        _model = pipeline.Fit(data);

        // Evaluate on training data (acceptable only for this small demo dataset)
        var predictions = _model.Transform(data);
        var metrics = _mlContext.MulticlassClassification.Evaluate(predictions);
        _metrics = new EvaluationMetrics
        {
            MacroAccuracy = metrics.MacroAccuracy,
            MicroAccuracy = metrics.MicroAccuracy,
            LogLoss = metrics.LogLoss,
            LogLossReduction = metrics.LogLossReduction
        };

        // Cache the ordered label names for mapping Score array → category
        var labelColumn = predictions.Schema["Label"];
        var slotNames = new VBuffer<ReadOnlyMemory<char>>();
        labelColumn.GetKeyValues(ref slotNames);
        _categoryLabels = slotNames.DenseValues()
            .Select(v => v.ToString()).ToArray();

        _logger.LogInformation(
            "Model trained — MacroAccuracy: {MacroAccuracy:F4}, MicroAccuracy: {MicroAccuracy:F4}, LogLoss: {LogLoss:F4}",
            _metrics.MacroAccuracy, _metrics.MicroAccuracy, _metrics.LogLoss);
    }

    public ClassificationResult Predict(TicketRequest request)
    {
        if (_model is null || _categoryLabels is null)
            throw new InvalidOperationException("Model has not been trained.");

        var engine = _mlContext.Model
            .CreatePredictionEngine<TicketInput, TicketPrediction>(_model);

        var input = new TicketInput
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = engine.Predict(input);

        var confidence = new Dictionary<string, float>();
        for (var i = 0; i < _categoryLabels.Length; i++)
        {
            confidence[_categoryLabels[i]] = prediction.Score[i];
        }

        return new ClassificationResult
        {
            PredictedCategory = prediction.PredictedCategory,
            Confidence = confidence
        };
    }
}

using Microsoft.AspNetCore.Mvc;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketsController : ControllerBase
{
    private readonly TicketClassifierService _classifier;

    public TicketsController(TicketClassifierService classifier)
    {
        _classifier = classifier;
    }

    /// <summary>Predict the category for a support ticket.</summary>
    [HttpPost("classify")]
    public ActionResult<ClassificationResult> Classify([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) || string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Subject and Description are required.");

        if (request.Priority is < 1 or > 3)
            return BadRequest("Priority must be between 1 and 3.");

        var result = _classifier.Predict(request);
        return Ok(result);
    }

    /// <summary>Return evaluation metrics from the last training run.</summary>
    [HttpGet("metrics")]
    public ActionResult<EvaluationMetrics> GetMetrics()
    {
        var metrics = _classifier.Metrics;
        if (metrics is null)
            return NotFound("Model has not been trained yet.");

        return Ok(metrics);
    }
}

