using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddSingleton<TicketClassifierService>();

var app = builder.Build();

// Train the model at startup using the bundled CSV
var classifier = app.Services.GetRequiredService<TicketClassifierService>();
var dataPath = Path.Combine(app.Environment.ContentRootPath, "Data", "tickets.csv");
classifier.TrainModel(dataPath);

app.MapPost("/api/tickets/classify", (TicketRequest request, TicketClassifierService svc) =>
{
    if (string.IsNullOrWhiteSpace(request.Subject) || string.IsNullOrWhiteSpace(request.Description))
        return Results.BadRequest("Subject and Description are required.");

    if (request.Priority is < 1 or > 3)
        return Results.BadRequest("Priority must be between 1 and 3.");

    return Results.Ok(svc.Predict(request));
});

app.MapGet("/api/tickets/metrics", (TicketClassifierService svc) =>
{
    var metrics = svc.Metrics;
    return metrics is null
        ? Results.NotFound("Model has not been trained yet.")
        : Results.Ok(metrics);
});

app.Run();

